import React, { Component } from 'react';
import { Link } from 'react-router-dom';

class Tabs extends Component {
  render() {
    return (
      <div className="tabs">
        <div className="navbar-tabs">
          <ul>
            <li>
              <Link to="/projects/web" className="nav-link">Web</Link>
            </li>
            <li>
              <Link to="/projects/app" className="nav-link">App</Link>
            </li>
            <li>
              <Link to="/projects/unity" className="nav-link">Unity</Link>
            </li>
            <li>
              <Link to="/projects/videos" className="nav-link">Videos</Link>
            </li>
            <li>
              <Link to="/projects/misc" className="nav-link">Misc.</Link>
            </li>  
          </ul>
        </div>
      </div>
    )
  }
}

export default Tabs;
